  w.writeMap(value.counts, (_w, _k) => { _w.writeString(_k); }, (_w, _v) => { _w.writeU64(_v); });
  w.writeOptional(value.maybeText, (_w, _v) => { _w.writeString(_v); });
  w.writeOptional(value.maybePatch, (_w, _v) => { _w.writeU64(_rt.cloneObjectHandle('uniffi_coverall_demo_fn_clone_patch', _v._handle)); });
  w.writeOptional(value.maybeU8, (_w, _v) => { _w.writeU8(_v); });
  w.writeOptional(value.maybeU16, (_w, _v) => { _w.writeU16(_v); });
  w.writeOptional(value.maybeU64, (_w, _v) => { _w.writeU64(_v); });
  w.writeOptional(value.maybeI8, (_w, _v) => { _w.writeI8(_v); });
  w.writeOptional(value.maybeI64, (_w, _v) => { _w.writeI64(_v); });
  w.writeOptional(value.maybeF32, (_w, _v) => { _w.writeF32(_v); });
  w.writeOptional(value.maybeF64, (_w, _v) => { _w.writeF64(_v); });
